CREATE OR REPLACE FUNCTION OFSERM.FX_CONTRACTS_INV_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_INVESTMENT_EXPOSURES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,F_INSTR_PORT_INFO_RECD_FLAG,N_INSTRUMENT_SKEY,N_ISSUE_SKEY,F_CORE_INVESTMENT_COMPANY_IND,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_EXP_FUND_CCY_SAME_IND,F_INTERNAL_CUST_IND,F_PAST_DUE_FLAG,F_REGULATORY_PARTY_INDICATOR,F_SOLVENCY_IND,N_ACCRUED_INT,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_EFF_MATURITY,N_EL_AMOUNT,N_EXCHANGE_RATE,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_GENERAL_PROVISION_AMT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_ORIGINAL_MATURITY,N_INSTR_OTH_VALUATION_ADJ_AMT,N_PRE_MITIGATION_EL_AMT,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_UNCOVERED_RWA_UL,N_UNDERLYING_TYPE_SKEY,N_INSTR_VALUATION_ADJ_AMOUNT,N_WRITE_OFF_AMT,V_DATA_SOURCE,V_EXP_RCY_CODE,N_ENTITY_SKEY,F_CREDIT_IMPAIRMENT_FLAG,F_DR_MATERIALITY_FLAG,F_EXP_TREATED_AS_HIGH_RISK,F_FINANCIAL_ASSET_IFRS9_FLAG,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_ADJUSTED_LGD_PERCENT,N_CCF_OWN_ESTIMATE,N_DVA_AMOUNT,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_RUN_PARAMETER_SETUP_SKEY,F_BUYER_SELLER_IND,F_FAILED_TRADE_FLAG,F_MATERIALITY_FLAG,F_SECURED_IND,N_FAILED_BUSINESS_DAYS,N_LOAD_RUN_ID,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),DIM_INSTRUMENT_CONTRACT.F_PERIOD_PORT_INFO_RECD_FLAG,to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),CASE WHEN DIM_COUNTRY.V_CURRENCY_CODE=STG_FX_CONTRACTS.V_BOUGHT_CURR_CODE THEN 'Y' ELSE 'N' END,CASE  WHEN INTERNAL_ENTITY.V_PARTY_ID IS NOT NULL  AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR') THEN  'Y' ELSE 'N'   END,CASE WHEN COALESCE(DIM_INSTRUMENT_CONTRACT.V_BOND_STATUS_CD,'Z') = 'P' THEN 'Y' ELSE 'N' END,DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,NVL(DIM_INSTRUMENT_CONTRACT.F_SOLVENCY_IND,STG_FX_CONTRACTS.F_SOLVENCY_IND),STG_FX_CONTRACTS.N_ACCRUED_INTEREST * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'0',CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,CASE WHEN FSI_ACCT_MODELING_INFO.N_EFF_MATURITY IS NULL THEN DAYS_BETWEEN(STG_FX_CONTRACTS.FIC_MIS_DATE,STG_FX_CONTRACTS.D_MATURITY_DATE,STG_FX_CONTRACTS.V_DAY_COUNT_IND) ELSE FSI_ACCT_MODELING_INFO.N_EFF_MATURITY END,'0',FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,COALESCE(STG_FX_CONTRACTS.N_BUY_AMT,STG_FX_CONTRACTS.N_SELL_AMT) * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'0','0',FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,DAYS_BETWEEN(STG_FX_CONTRACTS.D_EFFECTIVE_DATE,STG_FX_CONTRACTS.D_MATURITY_DATE,STG_FX_CONTRACTS.V_DAY_COUNT_IND),FSI_INSTR_VALUATION_DETAILS.N_OTHER_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'0','0',DAYS_BETWEEN(STG_FX_CONTRACTS.FIC_MIS_DATE,STG_FX_CONTRACTS.D_MATURITY_DATE,STG_FX_CONTRACTS.V_DAY_COUNT_IND),'870','0','0',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT*A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,'0',DIM_EXPOSURE_UNDERLYING_TYPE.N_UNDERLYING_TYPE_SKEY,FSI_INSTR_VALUATION_DETAILS.N_VALUATION_ADJ_AMOUNT * C_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,STG_FX_CONTRACTS.N_WRITEOFF_AMT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,'STG_FX_CONTRACTS',RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_DR_MATERIALITY_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,FSI_ACCT_MODELING_INFO.F_PREF_TREATMENT_FLAG,FSI_ACCT_MODELING_INFO.F_RW_BY_DISCRETION,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY),STG_FX_CONTRACTS.F_BUY_SELL_IND,STG_FX_CONTRACTS.F_FAILED_TRADE_FLAG,STG_FX_CONTRACTS.F_MATERIALITY_FLAG,STG_FX_CONTRACTS.F_SECURED_IND,to_char(STG_FX_CONTRACTS.N_FAILED_BUSINESS_DAYS),to_char(STG_FX_CONTRACTS.N_LOAD_RUN_ID),STG_FX_CONTRACTS.V_BOUGHT_CURR_CODE FROM STG_FX_CONTRACTS INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND STG_FX_CONTRACTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON STG_FX_CONTRACTS.V_CONTRACT_CODE = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND STG_FX_CONTRACTS.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) LEFT JOIN DIM_PARTY ON COALESCE(STG_FX_CONTRACTS.V_CUST_REF_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_REG ON DIM_ORG_STRUCTURE_REG.V_ENTITY_CODE = STG_FX_CONTRACTS.V_LV_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_REG.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_REG.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT JOIN DIM_PRODUCT ON STG_FX_CONTRACTS.V_PRODUCT_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY INNER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY AND DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CODE IN ('FRS') LEFT JOIN DIM_LOB ON STG_FX_CONTRACTS.V_LOB_CODE = DIM_LOB.V_LOB_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.D_RECORD_START_DATE AND DIM_LOB.D_RECORD_END_DATE LEFT JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_FX_CONTRACTS.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID = COALESCE(STG_FX_CONTRACTS.V_COUNTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT JOIN DIM_NETTING_AGREEMENT ON DIM_NETTING_AGREEMENT.V_NETTING_AGREEMENT_CODE = STG_FX_CONTRACTS.V_NETTING_AGREEMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_NETTING_AGREEMENT.D_RECORD_START_DATE AND DIM_NETTING_AGREEMENT.D_RECORD_END_DATE LEFT JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT JOIN FCT_ENTITY_INFO INTERNAL_ENTITY ON INTERNAL_ENTITY.V_PARTY_ID = STG_FX_CONTRACTS.V_CUST_REF_CODE AND INTERNAL_ENTITY.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND INTERNAL_ENTITY.N_RUN_SKEY = '870' AND INTERNAL_ENTITY.F_CAP_CONSL_ENTITY_IND = 'Y' LEFT JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.N_BASEL_CAP_CONSL_APPR_SKEY = INTERNAL_ENTITY.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR_CUST.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) LEFT JOIN DIM_GEOGRAPHY ON COALESCE(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = COALESCE(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT JOIN DIM_ISSUE ON COALESCE(STG_FX_CONTRACTS.V_CONTRACT_CODE, DIM_EXPOSURE.V_EXPOSURE_ID) = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = '870' AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT JOIN DIM_EXPOSURE DIM_HEDGED_EXPOSURE ON DIM_EXPOSURE.N_ACCT_SKEY = DIM_HEDGED_EXPOSURE.N_ACCT_SKEY AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HEDGED_EXPOSURE.D_RECORD_START_DATE AND DIM_HEDGED_EXPOSURE.D_RECORD_END_DATE LEFT JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT JOIN DIM_BUSINESS_UNIT ON STG_FX_CONTRACTS.V_BUSINESS_UNIT_CODE = DIM_BUSINESS_UNIT.V_BUSINESS_UNIT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BUSINESS_UNIT.D_RECORD_START_DATE AND DIM_BUSINESS_UNIT.D_RECORD_END_DATE LEFT JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_FX_CONTRACTS.V_INSTRUMENT_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT JOIN DIM_HOLDING_TYPE ON DIM_HOLDING_TYPE.V_HOLDING_TYPE = STG_FX_CONTRACTS.V_HOLDING_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HOLDING_TYPE.D_RECORD_START_DATE AND DIM_HOLDING_TYPE.D_RECORD_END_DATE LEFT JOIN DIM_STANDARD_PARTY_TYPE ON DIM_STANDARD_PARTY_TYPE.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_FX_CONTRACTS.V_BOUGHT_CURR_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV